import React from 'react';
import { BrowserRouter, Routes, Route, useLocation } from 'react-router-dom';
import BottomNav from './components/BottomNav';
import SplashScreen from './screens/SplashScreen';
import HomeDashboard from './screens/HomeDashboard';
import EnergyTracker from './screens/EnergyTracker';
import Education from './screens/Education';
import SmartTips from './screens/SmartTips';
import CommunityProfile from './screens/CommunityProfile';
import { useState, useEffect } from 'react';

function AppContent() {
  const [showSplash, setShowSplash] = useState(true);
  const location = useLocation();

  useEffect(() => {
    // Only show splash on initial load
    const timer = setTimeout(() => setShowSplash(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  if (showSplash) {
    return <SplashScreen />;
  }

  // Screens that shouldn't show the bottom nav
  const noNavRoutes = ['/welcome'];
  const showNav = !noNavRoutes.includes(location.pathname);

  return (
    <>
      <div className="app-content">
        <Routes>
          <Route path="/" element={<HomeDashboard />} />
          <Route path="/tracker" element={<EnergyTracker />} />
          <Route path="/learn" element={<Education />} />
          <Route path="/tips" element={<SmartTips />} />
          <Route path="/profile" element={<CommunityProfile />} />
        </Routes>
      </div>
      {showNav && <BottomNav activePath={location.pathname} />}
    </>
  );
}

function App() {
  // Theme initialization
  useEffect(() => {
    const isDark = localStorage.getItem('ecoTheme') === 'dark';
    if (isDark) {
      document.documentElement.setAttribute('data-theme', 'dark');
    }
  }, []);

  return (
    <div className="mobile-app-container">
      <BrowserRouter>
        <AppContent />
      </BrowserRouter>
    </div>
  );
}

export default App;

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Home, Activity, BookOpen, Lightbulb, User } from 'lucide-react';

const BottomNav = ({ activePath }) => {
    const navigate = useNavigate();

    const navItems = [
        { path: '/', icon: Home, label: 'Home' },
        { path: '/tracker', icon: Activity, label: 'Tracker' },
        { path: '/learn', icon: BookOpen, label: 'Learn' },
        { path: '/tips', icon: Lightbulb, label: 'Tips' },
        { path: '/profile', icon: User, label: 'Profile' },
    ];

    return (
        <div className="bottom-nav">
            {navItems.map((item) => {
                const Icon = item.icon;
                const isActive = activePath === item.path || (item.path !== '/' && activePath.startsWith(item.path));

                return (
                    <div
                        key={item.path}
                        className={`nav-item ${isActive ? 'active' : ''}`}
                        onClick={() => navigate(item.path)}
                    >
                        <div className="nav-icon-wrapper">
                            <Icon size={24} strokeWidth={isActive ? 2.5 : 2} />
                            {isActive && (
                                <div style={{ position: 'absolute', bottom: -8, width: 4, height: 4, backgroundColor: 'var(--primary-green)', borderRadius: '50%' }} />
                            )}
                        </div>
                        <span style={{ fontSize: '10px', marginTop: '2px', fontWeight: isActive ? '600' : '400' }}>
                            {item.label}
                        </span>
                    </div>
                );
            })}
        </div>
    );
};

export default BottomNav;

import React, { useState, useEffect } from 'react';
import { Award, Trophy, User, Settings, Moon, Bell, ChevronRight, LogOut, Medal } from 'lucide-react';

const CommunityProfile = () => {
    const [loaded, setLoaded] = useState(false);
    const [activeTab, setActiveTab] = useState('profile');
    const [darkMode, setDarkMode] = useState(localStorage.getItem('ecoTheme') === 'dark');

    useEffect(() => {
        setTimeout(() => setLoaded(true), 150);
    }, []);

    const toggleTheme = () => {
        const newDarkMode = !darkMode;
        setDarkMode(newDarkMode);
        if (newDarkMode) {
            document.documentElement.setAttribute('data-theme', 'dark');
            localStorage.setItem('ecoTheme', 'dark');
        } else {
            document.documentElement.removeAttribute('data-theme');
            localStorage.setItem('ecoTheme', 'light');
        }
    };

    return (
        <div className={`page-transition ${loaded ? '' : 'opacity-0'}`} style={{ padding: '20px', transition: 'opacity 0.3s ease' }}>

            {/* Header Tabs */}
            <div style={{ display: 'flex', backgroundColor: 'var(--border-light)', borderRadius: '12px', padding: '4px', marginBottom: '24px', marginTop: '12px' }}>
                <button
                    onClick={() => setActiveTab('profile')}
                    style={{ flex: 1, border: 'none', background: activeTab === 'profile' ? 'white' : 'transparent', color: activeTab === 'profile' ? 'var(--text-primary)' : 'var(--text-secondary)', padding: '10px', borderRadius: '8px', cursor: 'pointer', fontWeight: activeTab === 'profile' ? '600' : '500', boxShadow: activeTab === 'profile' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none' }}>
                    Profile
                </button>
                <button
                    onClick={() => setActiveTab('challenges')}
                    style={{ flex: 1, border: 'none', background: activeTab === 'challenges' ? 'white' : 'transparent', color: activeTab === 'challenges' ? 'var(--text-primary)' : 'var(--text-secondary)', padding: '10px', borderRadius: '8px', cursor: 'pointer', fontWeight: activeTab === 'challenges' ? '600' : '500', boxShadow: activeTab === 'challenges' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none' }}>
                    Challenges
                </button>
                <button
                    onClick={() => setActiveTab('community')}
                    style={{ flex: 1, border: 'none', background: activeTab === 'community' ? 'white' : 'transparent', color: activeTab === 'community' ? 'var(--text-primary)' : 'var(--text-secondary)', padding: '10px', borderRadius: '8px', cursor: 'pointer', fontWeight: activeTab === 'community' ? '600' : '500', boxShadow: activeTab === 'community' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none' }}>
                    Community
                </button>
            </div>

            {activeTab === 'profile' && (
                <div className="animate-fade-in">
                    {/* User ID block */}
                    <div className="flex-center" style={{ flexDirection: 'column', marginBottom: '32px' }}>
                        <div style={{ width: '90px', height: '90px', borderRadius: '50%', backgroundColor: 'var(--accent-light)', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '16px', border: '3px solid white', boxShadow: 'var(--shadow-soft)' }}>
                            <User size={40} color="var(--primary-green-dark)" />
                        </div>
                        <h2 className="h2" style={{ margin: 0 }}>Alex Johnson</h2>
                        <p className="caption" style={{ color: 'var(--primary-green)', fontWeight: '600', marginTop: '4px' }}>Level 12 Eco Warrior</p>
                    </div>

                    <h3 className="h3" style={{ marginBottom: '16px' }}>Settings</h3>
                    <div className="card" style={{ padding: '0' }}>
                        <div className="flex-row-between" style={{ padding: '16px', borderBottom: '1px solid var(--border-light)' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <Moon size={20} color="var(--text-secondary)" />
                                <span style={{ fontWeight: '500' }}>Dark Mode</span>
                            </div>
                            <div
                                onClick={toggleTheme}
                                style={{ width: '44px', height: '24px', backgroundColor: darkMode ? 'var(--primary-green)' : 'var(--border-light)', borderRadius: '12px', position: 'relative', cursor: 'pointer', transition: 'background-color 0.3s' }}>
                                <div style={{ position: 'absolute', top: '2px', left: darkMode ? '22px' : '2px', width: '20px', height: '20px', backgroundColor: 'white', borderRadius: '50%', transition: 'left 0.3s', boxShadow: '0 2px 4px rgba(0,0,0,0.2)' }} />
                            </div>
                        </div>
                        <div className="flex-row-between" style={{ padding: '16px', borderBottom: '1px solid var(--border-light)' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <Bell size={20} color="var(--text-secondary)" />
                                <span style={{ fontWeight: '500' }}>Daily Notifications</span>
                            </div>
                            <div style={{ width: '44px', height: '24px', backgroundColor: 'var(--primary-green)', borderRadius: '12px', position: 'relative', cursor: 'pointer' }}>
                                <div style={{ position: 'absolute', top: '2px', left: '22px', width: '20px', height: '20px', backgroundColor: 'white', borderRadius: '50%', boxShadow: '0 2px 4px rgba(0,0,0,0.2)' }} />
                            </div>
                        </div>
                        <div className="flex-row-between" style={{ padding: '16px', color: 'var(--danger)', cursor: 'pointer' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                <LogOut size={20} />
                                <span style={{ fontWeight: '500' }}>Sign Out</span>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'challenges' && (
                <div className="animate-fade-in">
                    <div className="card" style={{ backgroundColor: 'var(--accent-light)', border: 'none', display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{ backgroundColor: 'white', padding: '16px', borderRadius: '50%', boxShadow: 'var(--shadow-soft)' }}>
                            <Trophy size={32} color="var(--primary-yellow)" fill="var(--primary-yellow)" />
                        </div>
                        <div>
                            <p className="caption" style={{ color: 'var(--primary-green-dark)', fontWeight: '600' }}>YOUR ECO POINTS</p>
                            <h2 className="h1" style={{ color: 'var(--primary-green)', margin: '4px 0 0 0' }}>1,250</h2>
                        </div>
                    </div>

                    <h3 className="h3" style={{ marginTop: '24px', marginBottom: '16px' }}>Weekly Challenges</h3>

                    <div className="card" style={{ borderLeft: '4px solid var(--primary-green)' }}>
                        <div className="flex-row-between" style={{ marginBottom: '12px' }}>
                            <h3 className="h3" style={{ fontSize: '15px' }}>Zero Standby Weekend</h3>
                            <span style={{ backgroundColor: '#D1FAE5', color: 'var(--primary-green-dark)', padding: '4px 8px', borderRadius: '12px', fontSize: '12px', fontWeight: '600' }}>+100 pts</span>
                        </div>
                        <p className="p-text" style={{ fontSize: '13px', marginBottom: '12px' }}>Unplug all non-essential appliances this weekend.</p>
                        <div style={{ width: '100%', height: '8px', backgroundColor: 'var(--border-light)', borderRadius: '4px' }}>
                            <div style={{ width: '70%', height: '100%', backgroundColor: 'var(--primary-green)', borderRadius: '4px' }}></div>
                        </div>
                        <p className="caption" style={{ marginTop: '8px', textAlign: 'right' }}>2 Days Left</p>
                    </div>

                    <div className="card" style={{ borderLeft: '4px solid var(--border-light)' }}>
                        <div className="flex-row-between" style={{ marginBottom: '12px' }}>
                            <h3 className="h3" style={{ fontSize: '15px', color: 'var(--text-secondary)' }}>Log 5 Days in a Row</h3>
                            <span style={{ backgroundColor: '#F3F4F6', color: 'var(--text-secondary)', padding: '4px 8px', borderRadius: '12px', fontSize: '12px', fontWeight: '600' }}>+50 pts</span>
                        </div>
                        <button className="btn-secondary" style={{ padding: '8px', fontSize: '14px' }}>Start Challenge</button>
                    </div>

                </div>
            )}

            {activeTab === 'community' && (
                <div className="animate-fade-in">
                    <div style={{ textAlign: 'center', marginBottom: '24px' }}>
                        <h2 className="h2" style={{ marginBottom: '8px' }}>Global Leaderboard</h2>
                        <p className="p-text">Join thousands of others saving the planet.</p>
                    </div>

                    <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
                        {[
                            { rank: 1, name: 'Sarah M.', points: 4500, color: '#FBBF24' },
                            { rank: 2, name: 'David L.', points: 4120, color: '#9CA3AF' },
                            { rank: 3, name: 'Elena R.', points: 3950, color: '#B45309' },
                            { rank: 4, name: 'Alex Johnson', points: 1250, color: 'transparent', current: true },
                        ].map((user, i) => (
                            <div key={i} className="flex-row-between" style={{ padding: '16px', borderBottom: i !== 3 ? '1px solid var(--border-light)' : 'none', backgroundColor: user.current ? 'var(--accent-light)' : 'transparent' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                    <div style={{ width: '28px', fontWeight: '700', color: user.rank <= 3 ? user.color : 'var(--text-secondary)', textAlign: 'center' }}>
                                        {user.rank <= 3 ? <Medal size={24} color={user.color} fill={user.color} /> : `#${user.rank}`}
                                    </div>
                                    <div style={{ width: '36px', height: '36px', borderRadius: '50%', backgroundColor: 'var(--border-light)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                        <User size={18} color="var(--text-secondary)" />
                                    </div>
                                    <span style={{ fontWeight: user.current ? '700' : '500', color: user.current ? 'var(--primary-green-dark)' : 'var(--text-primary)' }}>{user.name} {user.current && '(You)'}</span>
                                </div>
                                <span style={{ fontWeight: '600', color: 'var(--primary-green)' }}>{user.points} pt</span>
                            </div>
                        ))}
                    </div>
                </div>
            )}

        </div>
    );
};

export default CommunityProfile;

import React, { useState, useEffect } from 'react';
import { Globe, Sun, Wind, Droplets, ChevronRight } from 'lucide-react';

const InfoCard = ({ title, desc, icon: Icon, color, bg }) => (
    <div className="card" style={{ display: 'flex', flexDirection: 'column', padding: '20px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px', marginBottom: '12px' }}>
            <div style={{ backgroundColor: bg, padding: '12px', borderRadius: '16px' }}>
                <Icon size={28} color={color} />
            </div>
            <h2 className="h2" style={{ margin: 0, color: 'var(--text-primary)' }}>{title}</h2>
        </div>
        <p className="p-text" style={{ fontSize: '15px' }}>{desc}</p>
        <div style={{ marginTop: '16px', display: 'flex', alignItems: 'center', color: color, fontWeight: '600', fontSize: '14px', cursor: 'pointer' }}>
            Learn More <ChevronRight size={16} style={{ marginLeft: '4px' }} />
        </div>
    </div>
);

const Education = () => {
    const [loaded, setLoaded] = useState(false);

    useEffect(() => {
        setTimeout(() => setLoaded(true), 150);
    }, []);

    return (
        <div className={`page-transition ${loaded ? '' : 'opacity-0'}`} style={{ padding: '20px', transition: 'opacity 0.3s ease' }}>

            <div style={{ marginBottom: '24px', marginTop: '12px' }}>
                <h1 className="h1">Learn</h1>
                <p className="p-text" style={{ marginTop: '4px' }}>Discover the power of clean energy</p>
            </div>

            {/* SDG 7 Banner */}
            <div className="card" style={{ backgroundColor: '#00558A', color: 'white', border: 'none', padding: '24px', position: 'relative', overflow: 'hidden' }}>
                <div style={{ position: 'relative', zIndex: 2 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' }}>
                        <Globe size={24} color="#FBBF24" />
                        <span style={{ fontSize: '14px', fontWeight: 'bold', letterSpacing: '1px', color: '#FBBF24', textTransform: 'uppercase' }}>UN Goal 7</span>
                    </div>
                    <h2 style={{ fontSize: '22px', fontWeight: '800', marginBottom: '8px', lineHeight: 1.2 }}>Affordable & Clean Energy</h2>
                    <p style={{ opacity: 0.9, fontSize: '14px', lineHeight: 1.5, maxWidth: '85%' }}>Ensure access to affordable, reliable, sustainable and modern energy for all by 2030.</p>
                </div>
                {/* Decorative circle */}
                <div style={{ position: 'absolute', right: '-40px', bottom: '-40px', width: '150px', height: '150px', backgroundColor: 'rgba(255,255,255,0.1)', borderRadius: '50%', zIndex: 1 }}></div>
            </div>

            <h2 className="h2" style={{ marginTop: '32px', marginBottom: '16px' }}>Energy Sources</h2>

            <InfoCard
                title="Solar Power"
                desc="Solar energy is derived from the sun's radiation and converted into electricity or heat. It's the most abundant energy source on Earth."
                icon={Sun}
                color="#D97706"
                bg="#FEF3C7"
            />

            <InfoCard
                title="Wind Energy"
                desc="Wind turbines capture the kinetic energy from wind and turn it into electricity. It's one of the fastest-growing clean energy sources."
                icon={Wind}
                color="#0369A1"
                bg="#E0F2FE"
            />

            <InfoCard
                title="Hydropower"
                desc="Hydropower relies on the water cycleΓÇöunderstanding how water evaporates and falls as rain or snowΓÇöto generate electricity."
                icon={Droplets}
                color="#0EA5E9"
                bg="#E0F2FE"
            />

        </div>
    );
};

export default Education;

import React, { useState, useEffect } from 'react';
import { Plus, BarChart2, Lightbulb, CheckCircle2 } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const mockWeeklyData = [
    { day: 'Mon', kwh: 12 },
    { day: 'Tue', kwh: 14 },
    { day: 'Wed', kwh: 11 },
    { day: 'Thu', kwh: 16 },
    { day: 'Fri', kwh: 13 },
    { day: 'Sat', kwh: 18 },
    { day: 'Sun', kwh: 10 },
];

const mockMonthlyData = [
    { name: 'Week 1', kwh: 92 },
    { name: 'Week 2', kwh: 85 },
    { name: 'Week 3', kwh: 98 },
    { name: 'Week 4', kwh: 75 },
];

const EnergyTracker = () => {
    const [activeTab, setActiveTab] = useState('weekly');
    const [showForm, setShowForm] = useState(false);
    const [inputValue, setInputValue] = useState('');
    const [submitted, setSubmitted] = useState(false);
    const [loaded, setLoaded] = useState(false);

    useEffect(() => {
        setTimeout(() => setLoaded(true), 150);
    }, []);

    const handleLogEnergy = (e) => {
        e.preventDefault();
        if (inputValue) {
            setSubmitted(true);
            setTimeout(() => {
                setShowForm(false);
                setSubmitted(false);
                setInputValue('');
            }, 1500);
        }
    };

    const chartData = activeTab === 'weekly' ? mockWeeklyData : mockMonthlyData;
    const dataKey = activeTab === 'weekly' ? 'day' : 'name';

    return (
        <div className={`page-transition ${loaded ? '' : 'opacity-0'}`} style={{ padding: '20px', transition: 'opacity 0.3s ease' }}>

            <div className="flex-row-between" style={{ marginBottom: '24px', marginTop: '12px' }}>
                <h1 className="h1">Energy Tracker</h1>
                <button
                    onClick={() => setShowForm(!showForm)}
                    style={{ width: '40px', height: '40px', borderRadius: '50%', backgroundColor: 'var(--primary-green)', color: 'white', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', boxShadow: 'var(--shadow-soft)', transition: 'transform 0.2s' }}
                >
                    <Plus size={24} style={{ transform: showForm ? 'rotate(45deg)' : 'rotate(0deg)', transition: 'transform 0.2s' }} />
                </button>
            </div>

            {showForm && (
                <div className="card animate-fade-in" style={{ backgroundColor: 'var(--accent-light)', borderColor: 'var(--primary-green)', borderStyle: 'dashed' }}>
                    {!submitted ? (
                        <form onSubmit={handleLogEnergy}>
                            <h3 className="h3" style={{ marginBottom: '16px', color: 'var(--primary-green-dark)' }}>Log Today's Usage</h3>
                            <div style={{ display: 'flex', gap: '12px', marginBottom: '16px' }}>
                                <input
                                    type="number"
                                    value={inputValue}
                                    onChange={(e) => setInputValue(e.target.value)}
                                    placeholder="Enter kWh"
                                    style={{ flex: 1, padding: '12px 16px', borderRadius: '12px', border: '1px solid var(--border-light)', fontSize: '16px', outline: 'none' }}
                                    autoFocus
                                />
                            </div>
                            <button type="submit" className="btn-primary" style={{ padding: '12px' }}>Save Log</button>
                        </form>
                    ) : (
                        <div className="flex-center" style={{ flexDirection: 'column', padding: '16px', color: 'var(--primary-green-dark)' }}>
                            <CheckCircle2 size={48} style={{ marginBottom: '12px' }} />
                            <h3 className="h3">Energy Logged!</h3>
                            <p className="caption" style={{ marginTop: '4px' }}>Great job tracking your consumption.</p>
                        </div>
                    )}
                </div>
            )}

            {/* Tabs */}
            <div style={{ display: 'flex', backgroundColor: 'var(--border-light)', borderRadius: '12px', padding: '4px', marginBottom: '20px' }}>
                <div
                    style={{ flex: 1, textAlign: 'center', padding: '10px', borderRadius: '8px', cursor: 'pointer', backgroundColor: activeTab === 'weekly' ? 'white' : 'transparent', fontWeight: activeTab === 'weekly' ? '600' : '500', boxShadow: activeTab === 'weekly' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none', color: activeTab === 'weekly' ? 'var(--text-primary)' : 'var(--text-secondary)' }}
                    onClick={() => setActiveTab('weekly')}
                >
                    Weekly
                </div>
                <div
                    style={{ flex: 1, textAlign: 'center', padding: '10px', borderRadius: '8px', cursor: 'pointer', backgroundColor: activeTab === 'monthly' ? 'white' : 'transparent', fontWeight: activeTab === 'monthly' ? '600' : '500', boxShadow: activeTab === 'monthly' ? '0 2px 8px rgba(0,0,0,0.05)' : 'none', color: activeTab === 'monthly' ? 'var(--text-primary)' : 'var(--text-secondary)' }}
                    onClick={() => setActiveTab('monthly')}
                >
                    Monthly
                </div>
            </div>

            {/* Chart */}
            <div className="card" style={{ padding: '20px 16px', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                <div className="flex-row-between" style={{ width: '100%', marginBottom: '24px' }}>
                    <div>
                        <h2 className="h2" style={{ margin: 0 }}>{activeTab === 'weekly' ? '90 kWh' : '350 kWh'}</h2>
                        <p className="caption">Total this {activeTab === 'weekly' ? 'week' : 'month'}</p>
                    </div>
                    <div style={{ backgroundColor: 'var(--bg-primary)', padding: '8px', borderRadius: '50%' }}>
                        <BarChart2 size={24} color="var(--primary-green)" />
                    </div>
                </div>

                <div style={{ height: '220px', width: '100%' }}>
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={chartData} margin={{ top: 0, right: 0, left: -25, bottom: 0 }}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--border-light)" />
                            <XAxis dataKey={dataKey} axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: 'var(--text-secondary)' }} dy={10} />
                            <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: 'var(--text-secondary)' }} />
                            <Tooltip
                                cursor={{ fill: 'var(--accent-light)', opacity: 0.5 }}
                                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                            />
                            <Bar dataKey="kwh" fill="var(--primary-green)" radius={[4, 4, 0, 0]} />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Personalized Tip */}
            <div className="card" style={{ display: 'flex', gap: '16px', alignItems: 'flex-start', padding: '16px', backgroundColor: '#FEF3C7', borderColor: 'transparent' }}>
                <div style={{ backgroundColor: '#FDE68A', padding: '10px', borderRadius: '50%' }}>
                    <Lightbulb size={24} color="#D97706" />
                </div>
                <div style={{ flex: 1 }}>
                    <h3 className="h3" style={{ color: '#92400E' }}>Personalized Tip</h3>
                    <p className="p-text" style={{ color: '#B45309', marginTop: '4px', fontSize: '13px' }}>Your usage was highest on Saturday. Try unplugging standby devices over the weekend to save up to 5 kWh!</p>
                </div>
            </div>

        </div>
    );
};

export default EnergyTracker;

import React, { useState, useEffect } from 'react';
import { Bookmark, BookmarkCheck, Lightbulb, Zap, Sun, Wind, Droplet } from 'lucide-react';

const tipsData = [
    { id: 1, title: 'Switch to LED Lighting', desc: 'LED bulbs use up to 90% less energy and last 25 times longer than traditional incandescent bulbs.', category: 'Lighting', icon: Lightbulb },
    { id: 2, title: 'Fight Phantom Power', desc: 'Unplug electronics like chargers and TVs when not in use. Standby power can account for 10% of household electricity.', category: 'Appliances', icon: Zap },
    { id: 3, title: 'Wash with Cold Water', desc: 'Heating water accounts for 90% of the energy used by washing machines. Use cold water to save energy and protect clothes.', category: 'Water', icon: Droplet },
    { id: 4, title: 'Utilize Natural Light', desc: 'Open your blinds during the day to use natural sunlight for illumination and lower your electricity bill.', category: 'Habits', icon: Sun },
    // Missing Droplet import so let's just use Zap or Wind for placeholder
];

const SmartTips = () => {
    const [loaded, setLoaded] = useState(false);
    const [bookmarks, setBookmarks] = useState([1, 4]); // Mock initial bookmarks

    useEffect(() => {
        setTimeout(() => setLoaded(true), 150);
    }, []);

    const toggleBookmark = (id) => {
        if (bookmarks.includes(id)) {
            setBookmarks(bookmarks.filter(bId => bId !== id));
        } else {
            setBookmarks([...bookmarks, id]);
        }
    };

    return (
        <div className={`page-transition ${loaded ? '' : 'opacity-0'}`} style={{ padding: '20px', transition: 'opacity 0.3s ease' }}>

            <div style={{ marginBottom: '24px', marginTop: '12px' }}>
                <h1 className="h1">Smart Tips</h1>
                <p className="p-text" style={{ marginTop: '4px' }}>Daily actions to lower your footprint</p>
            </div>

            <div className="card" style={{ backgroundColor: 'var(--primary-green)', color: 'white', border: 'none', marginBottom: '24px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                    <Lightbulb size={24} color="#FDE047" fill="#FDE047" />
                    <h2 className="h2" style={{ color: 'white', margin: 0 }}>Tip of the Day</h2>
                </div>
                <p style={{ fontSize: '15px', lineHeight: 1.5, opacity: 0.9 }}>
                    Keep your fridge coil clean. Dust accumulation makes the motor work harder, increasing energy consumption by up to 30%.
                </p>
            </div>

            <div style={{ display: 'flex', gap: '8px', overflowX: 'auto', paddingBottom: '16px', margin: '0 -20px', padding: '0 20px', scrollbarWidth: 'none' }}>
                <div style={{ backgroundColor: 'var(--text-primary)', color: 'white', padding: '8px 16px', borderRadius: '20px', fontSize: '14px', fontWeight: '500', whiteSpace: 'nowrap' }}>All Tips</div>
                <div style={{ backgroundColor: 'var(--bg-secondary)', color: 'var(--text-primary)', border: '1px solid var(--border-light)', padding: '8px 16px', borderRadius: '20px', fontSize: '14px', fontWeight: '500', whiteSpace: 'nowrap' }}>Bookmarked</div>
                <div style={{ backgroundColor: 'var(--bg-secondary)', color: 'var(--text-primary)', border: '1px solid var(--border-light)', padding: '8px 16px', borderRadius: '20px', fontSize: '14px', fontWeight: '500', whiteSpace: 'nowrap' }}>Lighting</div>
                <div style={{ backgroundColor: 'var(--bg-secondary)', color: 'var(--text-primary)', border: '1px solid var(--border-light)', padding: '8px 16px', borderRadius: '20px', fontSize: '14px', fontWeight: '500', whiteSpace: 'nowrap' }}>Appliances</div>
            </div>

            <div style={{ marginTop: '16px' }}>
                {tipsData.map(tip => {
                    const isBookmarked = bookmarks.includes(tip.id);
                    const Icon = tip.icon || Zap;
                    return (
                        <div key={tip.id} className="card" style={{ display: 'flex', gap: '16px' }}>
                            <div style={{ backgroundColor: 'var(--accent-light)', height: '48px', width: '48px', borderRadius: '12px', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                <Icon size={24} color="var(--primary-green-dark)" />
                            </div>
                            <div style={{ flex: 1 }}>
                                <div className="flex-row-between">
                                    <span className="caption" style={{ color: 'var(--primary-green)', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' }}>{tip.category}</span>
                                    <div onClick={() => toggleBookmark(tip.id)} style={{ padding: '4px', margin: '-4px', cursor: 'pointer' }}>
                                        {isBookmarked ? <BookmarkCheck size={20} color="var(--primary-yellow)" fill="var(--primary-yellow)" /> : <Bookmark size={20} color="var(--text-secondary)" />}
                                    </div>
                                </div>
                                <h3 className="h3" style={{ margin: '4px 0 6px 0' }}>{tip.title}</h3>
                                <p className="p-text" style={{ fontSize: '13px' }}>{tip.desc}</p>
                            </div>
                        </div>
                    );
                })}
            </div>

        </div>
    );
};

export default SmartTips;

import React from 'react';
import { Leaf } from 'lucide-react';

const SplashScreen = () => {
    return (
        <div className="app-content flex-center animate-fade-in" style={{ backgroundColor: 'var(--primary-green)', color: 'white', position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, zIndex: 100 }}>
            <div style={{ textAlign: 'center' }}>
                <div className="animate-float" style={{ display: 'inline-block', marginBottom: '24px', backgroundColor: 'rgba(255,255,255,0.2)', padding: '24px', borderRadius: '50%' }}>
                    <Leaf size={64} color="white" strokeWidth={1.5} />
                </div>
                <h1 style={{ fontSize: '32px', fontWeight: '800', marginBottom: '8px', letterSpacing: '-0.5px' }}>EcoEnergy</h1>
                <p style={{ fontSize: '16px', opacity: 0.9, fontWeight: '500' }}>Powering a Sustainable Future</p>

                <div style={{ position: 'absolute', bottom: '60px', left: 0, right: 0, display: 'flex', justifyContent: 'center' }}>
                    <div style={{ width: '40px', height: '4px', backgroundColor: 'rgba(255,255,255,0.3)', borderRadius: '2px', overflow: 'hidden' }}>
                        <div style={{ width: '50%', height: '100%', backgroundColor: 'white', borderRadius: '2px', animation: 'progress 2s ease-in-out infinite' }}></div>
                    </div>
                </div>
                <style>{`
          @keyframes progress {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(200%); }
          }
        `}</style>
            </div>
        </div>
    );
};

export default SplashScreen;
